import { NavLink } from "react-router-dom";
import { Nav } from "react-bootstrap";

function Menu() {
    return (
        <Nav className='d-flex flex-row' style={{ backgroundColor: '#6FCF97', padding: 10 }}>
            <NavLink to='/home' className='p-2' style={({ isActive }) => ({
                color: isActive ? 'yellow' : 'white',
                textDecoration: 'none',
                fontSize: 18
            })}>HOME</NavLink>

            <NavLink to='/products' className='p-2' style={({ isActive }) => ({
                color: isActive ? 'yellow' : 'white',
                textDecoration: 'none',
                fontSize: 18
            })}>PRODUCTS</NavLink>
        </Nav>
    );
}

export default Menu;
